{_Index = 1, _Map = 0, _CoordX = 125, _CoordY = 125}, 
}



--N�o mexer nisso
local DROP_ITEM_RAND = {}

function DropSystem.InsertItem(item)
	if not CONFIG_DROP_SWITCH
	then
		return
	end

	InsertKey(DROP_ITEM_RAND, item)
end

function DropSystem.GetItemRandom(index, porcentagem)
	if not CONFIG_DROP_SWITCH
	then
		return
	end
	DROP_ITEM_RAND = {}
	
	if porcentagem == 1
	then
		for i in ipairs(CONFIG_DROP_SYSTEM_ITEM) do
			if CONFIG_DROP_SYSTEM_ITEM[i]._Index == index
			then
				qtd = (CONFIG_DROP_SYSTEM_ITEM[i]._Porcentagem/100)*10000
				for x = 1, qtd do
					DropSystem.InsertItem(CONFIG_DROP_SYSTEM_ITEM[i])
				end		
			end		
		end
	else
		for i in ipairs(CONFIG_DROP_SYSTEM_ITEM) do
			if CONFIG_DROP_SYSTEM_ITEM[i]._Index == index
			then
				DropSystem.InsertItem(CONFIG_DROP_SYSTEM_ITEM[i])
			end
		end
	end
	
	if #DROP_ITEM_RAND > 0
	then
		return DROP_ITEM_RAND[GetRand(1, #DROP_ITEM_RAND)]
	end
	
	return -1
end

function DropSystem.PlayerDropItem(aIndex, x, y, position)
	if not CONFIG_DROP_SWITCH
	then
		return
	end
	
	local player = User.new(aIndex)
	local pInv = Inventory.new(aIndex)
	
	local item_index = pInv:getIndex(position)
	
	for i in ipairs(CONFIG_DROP_SYSTEM) do
		local box_index = GET_ITEM(CONFIG_DROP_SYSTEM[i]._BoxSection, CONFIG_DROP_SYSTEM[i]._BoxIndex)
		
		local registerDrop = CONFIG_DROP_SYSTEM[i].registerDrop

		if item_index == GET_ITEM(CONFIG_DROP_SYSTEM[i]._BoxSection, CONFIG_DROP_SYSTEM[i]._BoxIndex) then	
			if CONFIG_DROP_SYSTEM[i]._type == 1
			then		
				if (CONFIG_DROP_SYSTEM[i]._Level == -1 or pInv:getLevel(position) == CONFIG_DROP_SYSTEM[i]._Level)
				then
					local NomeBox = CONFIG_DROP_SYSTEM[i]._NomeBox
					local NomePlayer = player:getName()
					local Item = DropSystem.GetItemRandom(CONFIG_DROP_SYSTEM[i]._Index, CONFIG_DROP_SYSTEM[i]._Porcentagem)
					
					if Item == -1
					then
						SendMessage(string.format("[Sistema] Houve um problema ao dropar o item, contate o administrador."), aIndex, 1)
						return 1
					end
					
					--if CONFIG_DROP_SYSTEM[i].ItemInventory
					--then
					--	for i = 13, MAX_INVENTORY_RANGE do
					--		if pInv:isItem(i) ~= 0
					--		then
					--			SendMessage(string.format("Seu inventario precisa estar vazio,[%s] no primeiro quadrado!", NomeBox), aIndex, 1)
					--			return 1
					--		end
					--	end
					--end
					
					if Item._Count == 0
					then
						if Item._AnuncioGlobal == 1
						then
							SendMessageGlobal(string.format("%s foi trolado ao dropar uma %s ;)", NomePlayer, NomeBox), 0)
							SendMessage(string.format("Voce foi trolado ao dropar a %s", NomeBox), aIndex, 1)			
						else
							SendMessage(string.format("Voce foi trolado ao dropar a %s ;)", NomeBox), aIndex, 1)
						end
						InventoryDeleteItem(aIndex, position)
						SendInventoryDeleteItem(aIndex, position)
						return 1
					end
					
					local exc = 0
					
					if Item._Exc_1 ~= 0
					then
						exc = exc + 1
					end
					if Item._Exc_2 ~= 0
					then
						exc = exc + 2
					end
					if Item._Exc_3 ~= 0
					then
						exc = exc + 4
					end
					if Item._Exc_4 ~= 0
					then
						exc = exc + 8
					end
					if Item._Exc_5 ~= 0
					then
						exc = exc + 16
					end
					if Item._Exc_6 ~= 0
					then
						exc = exc + 32
					end
					
					if Item._Section == 12 then
						exc = 31
					end

					for forcount = 1, Item._Count do
						if CONFIG_DROP_SYSTEM[i].ItemInventory
						then
							ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(Item._Section, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
							
							if Item._SetCompleto == 1
							then
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(8, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(9, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(10, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(11, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
							end
							
							if Item._KitAneis == 1
							then
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(Item._Section, Item._IndexRing), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(Item._Section, Item._IndexRing), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
							end
							
							if Item._KitSword == 1
							then
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(6, Item._IndexShield), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)							
							end
							
							if Item._DoisRings == 1
							then
								ItemSerialCreate(aIndex, 236, 0, 0, GET_ITEM(Item._Section, Item._IndexDoisRings), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)							
							end
						else
							local map = player:getMapNumber()
							ItemSerialCreate(aIndex,map, x, y, GET_ITEM(Item._Section, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
							
							if Item._SetCompleto == 1
							then
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(8, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(9, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(10, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(11, Item._IndexItem), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)			
							end
							
							if Item._KitAneis == 1
							then
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(Item._Section, Item._IndexRing), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(Item._Section, Item._IndexRing), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)		
							end
							
							if Item._KitSword == 1
							then
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(6, Item._IndexShield), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
							end
							
							if Item._DoisRings == 1
							then
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(Item._Section, Item._IndexDoisRings), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)
								ItemSerialCreate(aIndex,map, x, y, GET_ITEM(Item._Section, Item._IndexDoisRings), Item._Level, Item._Durabilidade, Item._Luck, Item._Skill, Item._Opt, exc)		
							end
							
						end					
					end	
					
					if Item._AnuncioGlobal == 1
					then
						SendMessageGlobal(string.format("[%s] %s dropou %s", NomeBox, NomePlayer, Item._NomeItem), 0)
						LogAdd(string.format("[DropGlobal] [%s] %s dropou uma [%s] %s.", player:getAccountID(), player:getName(), NomeBox, Item._NomeItem))
					end	
					
					InventoryDeleteItem(aIndex, position)
					SendInventoryDeleteItem(aIndex, position)
					
					if registerDrop then
						DataBase.SetAddValue(CONFIG_DROP_SYSTEM_RANKING.table, CONFIG_DROP_SYSTEM_RANKING.column, 1, CONFIG_DROP_SYSTEM_RANKING.where, player:getAccountID())
					end

					return 1
				end
			elseif CONFIG_DROP_SYSTEM[i]._type == 2
			then
				for t in ipairs(CONFIG_DROP_SYSTEM_PORTAL) do
					if CONFIG_DROP_SYSTEM[i]._Index == CONFIG_DROP_SYSTEM_PORTAL[t]._Index
					then
						Teleport(aIndex, CONFIG_DROP_SYSTEM_PORTAL[t]._Map, CONFIG_DROP_SYSTEM_PORTAL[t]._CoordX, CONFIG_DROP_SYSTEM_PORTAL[t]._CoordY)
					end
				end						
				InventoryDeleteItem(aIndex, position)
				SendInventoryDeleteItem(aIndex, position)
				return 1
			end
		end
	end	
	return
end

GameServerFunctions.PlayerDropItem(DropSystem.PlayerDropItem)

return DropSystem